// ============================================================
// Node-RED Function node: Dragino LHT52 decoder
// LoRaWAN Temperature & Humidity Sensor (native LoRa, geen RS485)
//
// Payload FPORT=2 (11 bytes, raw hex via msg.payload.data):
//   [0-1] TempC_SHT  signed int16 BE / 100 → °C  (interne SHT20 sensor)
//   [2-3] Hum_SHT    uint16 BE / 10       → %RH
//   [4-5] TempC_DS   signed int16 BE / 100 → °C  (externe DS18B20 probe)
//                    0x7FFF = geen probe aangesloten
//   [6]   Ext flag   0x01 = DS18B20 probe type
//   [7-10] Unix timestamp uint32 BE
//
// Verschil met RS485-LB decoders (630ML1 e.d.):
//   RS485-LB: Base64 payload, floats IEEE754, batterij in bytes 0-1
//   LHT52:    Hex string payload, eigen byte formaat, geen batterij in FPORT=2
//             Batterij zit in FPORT=5 (device status uplink) → hier genegeerd
// ============================================================

const Dev = "ASSET_PLACEHOLDER";

const ID_TEMP_INTERN  = 6800;
const ID_HUMIDITY     = 6900;
const ID_TEMP_EXTERN  = 7500;

const mid = global.get("mid") || 0;

try {
    const port = msg.payload.port;

    // FPORT=5: device status (batterij, firmware) → negeren
    if (port === 5) return null;

    // Alleen FPORT=2 verwerken (realtime sensor data)
    // FPORT=3 = datalog (zelfde bytes maar andere volgorde, zelden gebruikt)
    if (port !== 2) return null;

    const raw = msg.payload.data;
    if (!raw || typeof raw !== "string" || raw.length < 14) {
        node.warn("LHT52: payload ontbreekt of te kort (" + (raw ? raw.length : 0) + " chars)");
        return null;
    }

    // Hex string naar bytes
    const b = [];
    for (let i = 0; i < raw.length; i += 2) {
        b.push(parseInt(raw.substr(i, 2), 16));
    }

    if (b.length < 7) {
        node.warn("LHT52: te weinig bytes: " + b.length);
        return null;
    }

    // Interne temperatuur (signed int16 via shift trick)
    const temp_intern = parseFloat(((b[0] << 24 >> 16 | b[1]) / 100).toFixed(2));

    // Vochtigheid (unsigned, nooit negatief)
    const humidity = parseFloat(((b[2] << 8 | b[3]) / 10).toFixed(1));

    // Externe temperatuur (DS18B20 probe)
    // 0x7FFF = geen probe → geen MD entry sturen
    const ext_raw = (b[4] << 8) | b[5];
    const has_probe = (ext_raw !== 0x7FFF);
    const temp_extern = has_probe
        ? parseFloat(((b[4] << 24 >> 16 | b[5]) / 100).toFixed(2))
        : null;

    // Timestamp: gebruik payload timestamp als RTC al gesynchroniseerd is
    // (unix = 0 of >2030 = device heeft nog geen tijd na join)
    let ts;
    if (b.length >= 11) {
        const unix = ((b[7] << 24) | (b[8] << 16) | (b[9] << 8) | b[10]) >>> 0;
        if (unix > 1000000000 && unix < 1900000000) {
            ts = new Date(unix * 1000).toISOString();
        } else {
            ts = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString();
        }
    } else {
        ts = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString();
    }

    // MD opbouwen
    const MD = [
        { Id: ID_TEMP_INTERN, Val: temp_intern },
        { Id: ID_HUMIDITY,    Val: humidity }
    ];

    if (has_probe && temp_extern !== null) {
        MD.push({ Id: ID_TEMP_EXTERN, Val: temp_extern });
    }

    // Radio metadata (zelfde als andere decoders)
    if (msg.snr  !== undefined) MD.push({ Id: 5400, Val: parseFloat(msg.snr)  });
    if (msg.rssi !== undefined) MD.push({ Id: 5500, Val: parseFloat(msg.rssi) });
    if (msg.dr?.spreadFactor !== undefined)
        MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });

    global.set("mid", mid + 1);

    msg.payload = {
        MID: mid,
        D: [{
            Dev: Dev,
            TS:  ts,
            ED:  [],
            MD:  MD
        }]
    };

    return msg;

} catch (e) {
    node.error("LHT52 decoder fout: " + e.message, msg);
    return null;
}
